// ── Inputs ──────────────────────────────────────────────────
const openaiResp = $input.first().json;
const prepData   = $node['Prepare Prompt — Sourcing'].json;

// ── Latency ──────────────────────────────────────────────────
const end_time   = Date.now();
const latency_ms = prepData.start_time ? (end_time - prepData.start_time) : null;

// ── Real token counts from OpenAI usage object ────────────────
const usage         = openaiResp.usage || {};
const prompt_tokens     = usage.prompt_tokens     || 0;
const completion_tokens = usage.completion_tokens || 0;
const total_tokens      = usage.total_tokens      || (prompt_tokens + completion_tokens);

// ── USD cost using model-specific rates ───────────────────────
const input_rate  = 0.00015;
const output_rate = 0.0006;
const estimated_usd = parseFloat(
  ((prompt_tokens / 1000 * input_rate) + (completion_tokens / 1000 * output_rate)).toFixed(6)
);

// ── Parse LLM response ────────────────────────────────────────
const raw = openaiResp.message?.content || openaiResp.text || '{}';
let parsed;
try {
  parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {
  parsed = { recommendation: raw, parse_error: e.message };
}

// ── Overwrite cost_of_insight with real numbers ───────────────
parsed.cost_of_insight = {
  model:              'gpt-4o-mini',
  prompt_tokens,
  completion_tokens,
  total_tokens,
  estimated_usd,
  input_rate_per_1k:  0.00015,
  output_rate_per_1k: 0.0006,
};

return [{ json: {
  agent: 'sourcing_quality',
  ...parsed,
  rag_context: prepData.rag_context,
  latency_ms,
  prompt_tokens,
  completion_tokens,
  total_tokens,
  estimated_usd,
  run_timestamp: new Date().toISOString(),
} }];

