const insights = $input.all().map(i => i.json);
const evaluated = insights.map(insight => {
  const hasRag = !!(insight.rag_context && insight.rag_context.length > 50);
  const scores = {
    actionability: insight.recommendation && insight.recommendation.length > 60 ? 1.0 : 0.5,
    grounding:     hasRag ? 1.0 : 0.3,
    confidence:    (insight.confidence_score || 0) >= 0.7 ? 1.0 : 0.6,
    schema_valid:  ['recommendation','evidence','confidence_score','cost_of_insight','alternative'].every(f => f in insight) ? 1.0 : 0.0,
    rag_grounded:  hasRag ? 1.0 : 0.0
  };
  const overall = Object.values(scores).reduce((a,b)=>a+b,0) / Object.keys(scores).length;
  return { ...insight, eval_scores: scores, eval_overall: parseFloat(overall.toFixed(2)), rag_grounded: hasRag };
});
return evaluated.map(e => ({ json: e }));

const insights = $input.all().map(i => i.json);

// ── Real totals from actual token usage ──────────────────────────
const totalUSD    = insights.reduce((s, i) => s + (i.estimated_usd   || 0), 0);
const totalTokens = insights.reduce((s, i) => s + (i.total_tokens    || 0), 0);
const totalPrompt = insights.reduce((s, i) => s + (i.prompt_tokens   || 0), 0);
const totalCompl  = insights.reduce((s, i) => s + (i.completion_tokens || 0), 0);
const ragGrounded = insights.filter(i => i.rag_grounded).length;

// ── Per-agent cost breakdown ──────────────────────────────────────
const costByAgent = insights.map(i => ({
  agent:             i.agent,
  model:             i.cost_of_insight?.model,
  prompt_tokens:     i.prompt_tokens     || 0,
  completion_tokens: i.completion_tokens || 0,
  total_tokens:      i.total_tokens      || 0,
  estimated_usd:     i.estimated_usd     || 0,
  latency_ms:        i.latency_ms        || null,
}));

// ── Latency stats ─────────────────────────────────────────────────
const latencies   = insights.map(i => i.latency_ms).filter(l => l !== null);
const avgLatency  = latencies.length
  ? Math.round(latencies.reduce((a,b) => a+b, 0) / latencies.length)
  : null;
const maxLatency  = latencies.length ? Math.max(...latencies) : null;
const slowAgent   = latencies.length
  ? insights.find(i => i.latency_ms === maxLatency)?.agent
  : null;

// ── Optimization suggestions based on real cost ───────────────────
const suggestions = [];
for (const a of costByAgent) {
  if (a.model === 'gpt-4o' && (a.estimated_usd || 0) > 0.001) {
    const saving = parseFloat((a.estimated_usd * 0.7).toFixed(6));
    suggestions.push(
      'Downgrade ' + a.agent + ' from gpt-4o to gpt-4o-mini '
      + '(est. saving $' + saving + ' per run, ~70% reduction).'
    );
  }
  if ((a.latency_ms || 0) > 8000) {
    suggestions.push(
      a.agent + ' latency is ' + a.latency_ms + 'ms — consider prompt compression to reduce tokens.'
    );
  }
}
if (!suggestions.length) suggestions.push('All agents within cost and latency targets.');

// ── Before/after optimization simulation ─────────────────────────
const gpt4oAgents = costByAgent.filter(a => a.model === 'gpt-4o');
const potentialSaving = gpt4oAgents.reduce((s, a) => s + (a.estimated_usd * 0.7), 0);

return [{ json: {
  optimization_report: {
    total_usd:             parseFloat(totalUSD.toFixed(6)),
    total_tokens:          totalTokens,
    total_prompt_tokens:   totalPrompt,
    total_completion_tokens: totalCompl,
    avg_latency_ms:        avgLatency,
    max_latency_ms:        maxLatency,
    slowest_agent:         slowAgent,
    rag_grounding_rate:    ragGrounded + '/' + insights.length,
    cost_by_agent:         costByAgent,
    potential_saving_usd:  parseFloat(potentialSaving.toFixed(6)),
    suggestions,
  },
  insights,
} }];

const { optimization_report, insights } = $input.first().json;
return [{ json: {
  status: 'complete',
  run_summary: {
    agents_run:          insights.length,
